import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{n as i,r as a,t as o}from"./chunks/vm-arguments.BmU0TYdw.js";const s=JSON.parse(`{"title":"Avviare il Gioco","description":"Impara come usare i vari profili d'avvio per avviare ed effettuare debug delle tue mod in un ambiente di gioco dal vivo.","frontmatter":{"title":"Avviare il Gioco","description":"Impara come usare i vari profili d'avvio per avviare ed effettuare debug delle tue mod in un ambiente di gioco dal vivo.","authors":["IMB11","Tenneb22"],"files":[]},"headers":[],"relativePath":"it_it/1.21.8/develop/getting-started/launching-the-game.md","filePath":"versions/1.21.8/translated/it_it/develop/getting-started/launching-the-game.md","lastUpdated":1760721669000}`);var c={name:`it_it/1.21.8/develop/getting-started/launching-the-game.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Avviare il Gioco <a class="header-anchor" href="#h1" aria-label="Permalink to “Avviare il Gioco”">​</a></h1><p>Loom di Fabric fornisce una varietà di profili d&#39;avvio che ti aiutano ad avviare ed effettuare debug delle tue mod in un ambiente di gioco live. Questa guida tratterà dei vari profili d&#39;avvio e di come usarli per effettuare debug e per testare le tue mod nel gioco.</p><h2 id="launch-profiles" tabindex="-1">Profili d&#39;Avvio <a class="header-anchor" href="#launch-profiles" aria-label="Permalink to “Profili d&#39;Avvio”">​</a></h2><p>Se stai usando IntelliJ IDEA, puoi trovare i profili d&#39;avvio nell&#39;angolo in alto a destra della finestra. Clicca sul menu a tendina per vedere i profili d&#39;avvio disponibili.</p><p>Dovrebbe esserci un profilo client e uno server, con l&#39;opzione di eseguire normalmente o in modalità debug:</p><p><img src="/assets/develop/getting-started/launch-profiles.png" alt="Profili d&#39;Avvio" loading="lazy"></p><h2 id="gradle-tasks" tabindex="-1">Operazioni Gradle <a class="header-anchor" href="#gradle-tasks" aria-label="Permalink to “Operazioni Gradle”">​</a></h2><p>Se stai usando la linea di comando, puoi usare i comandi Gradle seguenti per avviare il gioco:</p><ul><li><code>./gradlew runClient</code> - Avvia il gioco in modalità client.</li><li><code>./gradlew runServer</code> - Avvia il gioco in modalità server.</li></ul><p>L&#39;unico problema con questo approccio è che non puoi facilmente effettuare il debug del tuo codice. Se vuoi effettuare debug del tuo codice, avrai bisogno di usare i profili d&#39;avvio in IntelliJ IDEA o tramite l&#39;integrazione Gradle del tuo IDE.</p><h2 id="hotswapping-classes" tabindex="-1">Hotswapping delle Classi <a class="header-anchor" href="#hotswapping-classes" aria-label="Permalink to “Hotswapping delle Classi”">​</a></h2><p>Quando esegui il gioco in modalità debug, puoi fare hotswap (&quot;scambio a caldo&quot;) delle tue classe senza riavviare il gioco. Questo è utile per testare cambiamenti al tuo codice velocemente.</p><p>Tuttavia ci sono alcune limitazioni:</p><ul><li>Non puoi aggiungere né rimuovere metodi</li><li>Non puoi cambiare i parametri dei metodi</li><li>Non puoi aggiungere né togliere attributi</li></ul><p>Tuttavia, usando il <a href="https://github.com/JetBrains/JetBrainsRuntime" target="_blank" rel="noreferrer">JetBrains Runtime</a>, puoi raggirare la maggior parte dei limiti, e addirittura aggiungere o togliere classi e metodi. Questo dovrebbe permettere alla maggior parte delle modifiche di essere applicate senza riavviare il gioco.</p><p>Non dimenticare di aggiungere ciò che segue all&#39;opzione Argomenti VM nella tua configurazione d&#39;avvio di Minecraft:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-XX:+AllowEnhancedClassRedefinition</span></span></code></pre></div><h2 id="hotswapping-mixins" tabindex="-1">Hotswapping dei Mixin <a class="header-anchor" href="#hotswapping-mixins" aria-label="Permalink to “Hotswapping dei Mixin”">​</a></h2><p>Se stai usando i Mixin, puoi fare hotswap delle tue classi Mixin senza riavviare il gioco. Questo è utile per testare cambiamenti ai tuoi Mixin velocemente.</p><p>Avrai bisogno d&#39;installare l&#39;agent Java Mixin perché questo funzioni.</p><h3 id="1-locate-the-mixin-library-jar" tabindex="-1">1. Trova il Jar della Libreria Mixin <a class="header-anchor" href="#1-locate-the-mixin-library-jar" aria-label="Permalink to “1. Trova il Jar della Libreria Mixin”">​</a></h3><p>In IntelliJ IDEA, puoi trovare il jar della libreria Mixin nella sezione &quot;Librerie Esterne&quot; della sezione &quot;Progetto&quot;:</p><p><img src="/assets/develop/getting-started/mixin-library.png" alt="Libreria Mixin" loading="lazy"></p><p>Dovrai copiare il &quot;Percorso Assoluto&quot; del jar per il prossimo passaggio.</p><h3 id="2-add-the--javaagent-vm-argument" tabindex="-1">2. Aggiungi l&#39;argomento VM <code>-javaagent</code> <a class="header-anchor" href="#2-add-the--javaagent-vm-argument" aria-label="Permalink to “2. Aggiungi l&#39;argomento VM -javaagent”">​</a></h3><p>Nella tua configurazione di avvio &quot;Client Minecraft &quot; e/o &quot;Server Minecraft&quot;, aggiungi ciò che segue all&#39;opzione Argomenti VM:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>-javaagent:&quot;percorso al jar della libreria mixin qui&quot;</span></span></code></pre></div><p><img src="/assets/develop/getting-started/vm-arguments.png" alt="Screenshot di Argomenti VM" loading="lazy"></p><p>Ora, dovresti poter modificare i contenuti dei tuoi metodi mixin durante il debugging e vedere gli effetti delle modifiche senza riavviare il gioco.</p>`,29)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};